        '"'  => out.appendSlice(_allocator, "\\\"") catch {},
        '\\' => out.appendSlice(_allocator, "\\\\") catch {},
        '\n' => out.appendSlice(_allocator, "\\n")  catch {},
        '\r' => out.appendSlice(_allocator, "\\r")  catch {},
        '\t' => out.appendSlice(_allocator, "\\t")  catch {},
