// ── Profile stdlib ────────────────────────────────────────────────────────────
const _ProfileEntry = struct { total_ns: i128, call_count: u64 };
var _profile_entries = std.StringHashMap(_ProfileEntry).init(std.heap.page_allocator);
var _profile_name_stack: std.ArrayList([]const u8) = .empty;
